     1|/**
     2| * IVX IA Reliability Gate — Single Decision Engine.
     3| *
     4| * Problem (owner spec): IVX IA sometimes returns contradictory messages in the
     5| * same conversation — "Task completed" + "Task blocked" + "I'll inspect now" +
     6| * "Open Developer Workspace" — which destroys trust.
     7| *
     8| * This gate enforces four owner-required rules, deterministically and with no I/O:
     9| *
    10| *  1. SINGLE DECISION ENGINE — every reply carries exactly ONE status, picked
    11| *     from a fixed state machine: READY | RUNNING | WAITING_OWNER | BLOCKED |
    12| *     FAILED | VERIFIED. Never mixed.
    13| *  2. NO GENERIC PROMISES — "I'll inspect now", "I'll fix it", "One moment",
    14| *     "hold on", "let me check" are blocked unless the answer also carries real
    15| *     evidence (a task id, files changed, commit SHA, deploy id, or live
    16| *     verification line). A promise without evidence is rewritten to UNVERIFIED.
    17| *  3. EVIDENCE-FIRST — any claim of Done / Fixed / Verified / Deployed must be
    18| *     backed by evidence fields (Task ID, Files changed, Commit SHA, Render
    19| *     Deploy ID, Live verification). Missing evidence → answer becomes
    20| *     "UNVERIFIED" with the exact missing artifact named.
    21| *  4. REMOVE CONTRADICTIONS — an answer that asserts a success state (Done /
    22| *     Completed / Verified / Deployed) AND a failure state (Blocked / Failed /
    23| *     Waiting) in the same message is contradictory. The gate resolves to the
    24| *     lower-confidence state and explains the event that caused the change.
    25| *
    26| * Pure + deterministic (no network, filesystem, or AI) so it is fully
    27| * unit-testable. It runs AFTER the senior-developer / access-status / execution
    28| * gates so it never re-implements their work — it only polishes the final answer
    29| * into a single-state, evidence-first reply.
    30| */
    31|export const IVX_IA_RELIABILITY_GATE_MARKER =
    32|  'ivx-ia-reliability-gate-2026-07-04-v1';
    33|
    34|/** The single allowed decision state for any IVX IA reply. */
    35|export type IVXIAState =
    36|  | 'READY'
    37|  | 'RUNNING'
    38|  | 'WAITING_OWNER'
    39|  | 'BLOCKED'
    40|  | 'FAILED'
    41|  | 'VERIFIED'
    42|  | 'UNVERIFIED';
    43|
    44|/** Evidence fields that turn a promise into a verifiable claim. */
    45|export type IVXIAEvidence = {
    46|  taskId?: string | null;
    47|  filesChanged?: string[] | null;
    48|  commitSha?: string | null;
    49|  renderDeployId?: string | null;
    50|  liveVerification?: string | null;
    51|};
    52|
    53|export type IVXIAReliabilityGateInput = {
    54|  message: string;
    55|  answer: string;
    56|  evidence?: IVXIAEvidence | null;
    57|};
    58|
    59|export type IVXIAReliabilityGateResult = {
    60|  answer: string;
    61|  gated: boolean;
    62|  state: IVXIAState;
    63|  contradictions: string[];
    64|  bannedPromises: string[];
    65|  missingEvidence: string[];
    66|  reason: string | null;
    67|};
    68|
    69|/**
    70| * Generic promise / filler phrases the owner explicitly banned. They are only
    71| * allowed when the answer also carries real evidence (task id / files / commit /
    72| * deploy / live verification); otherwise the promise is fabricated intent.
    73| */
    74|export const BANNED_GENERIC_PROMISES: readonly string[] = [
    75|  "i'll inspect",
    76|  "i will inspect",
    77|  "i'll fix",
    78|  "i will fix",
    79|  "i'll patch",
    80|  "i will patch",
    81|  "i'll validate",
    82|  "i will validate",
    83|  "i'll implement",
    84|  "i will implement",
    85|  "i'll return proof",
    86|  "i will return proof",
    87|  "i'll check",
    88|  "i will check",
    89|  "i'll look",
    90|  "i will look",
    91|  "i'll review",
    92|  "i will review",
    93|  "let me check",
    94|  "let me look",
    95|  "let me inspect",
    96|  "let me review",
    97|  "let me see",
    98|  'one moment',
    99|  'one sec',
   100|  'just a moment',
   101|  'just a second',
   102|  'give me a moment',
   103|  'give me a second',
   104|  'hold on',
   105|  'please wait',
   106|  'stand by',
   107|  'standby',
   108|  "i'll get back to you",
   109|  'i will get back to you',
   110|  'i will update you shortly',
   111|  "i'll update you shortly",
   112|  'checking now',
   113|  'executing that now',
   114|  'starting now',
   115|  'i am starting',
   116|  'i am inspecting',
   117|  'i am checking',
   118|  'i am executing',
   119|];
   120|
   121|/**
   122| * Success-state assertions. When any of these appear, the answer is claiming a
   123| * positive outcome and must carry evidence — otherwise it is a fabricated
   124| * completion claim.
   125| */
   126|const SUCCESS_STATE_PATTERNS: { pattern: RegExp; label: string }[] = [
   127|  { pattern: /\btask\s+completed\b/i, label: 'Task completed' },
   128|  { pattern: /\btask\s+done\b/i, label: 'Task done' },
   129|  { pattern: /\bdone\b/i, label: 'Done' },
   130|  { pattern: /\bcompleted\b/i, label: 'Completed' },
   131|  { pattern: /\bfinished\b/i, label: 'Finished' },
   132|  { pattern: /\bshipped\b/i, label: 'Shipped' },
   133|  { pattern: /\bfixed\b/i, label: 'Fixed' },
   134|  { pattern: /\bverified\b/i, label: 'Verified' },
   135|  { pattern: /\bdeployed\b/i, label: 'Deployed' },
   136|  { pattern: /\bdeploy\s+(?:is\s+)?live\b/i, label: 'Deploy live' },
   137|  { pattern: /\blive\s+in\s+production\b/i, label: 'Live in production' },
   138|  { pattern: /\ball\s+checks\s+pass(?:ed|ing)?\b/i, label: 'All checks passed' },
   139|  { pattern: /\btests?\s+passed\b/i, label: 'Tests passed' },
   140|  { pattern: /\bbuild\s+succeeded\b/i, label: 'Build succeeded' },
   141|];
   142|
   143|/**
   144| * Failure / waiting-state assertions. When one of these coexists with a success
   145| * assertion in the same answer, the reply is contradictory.
   146| */
   147|const FAILURE_STATE_PATTERNS: { pattern: RegExp; label: string }[] = [
   148|  { pattern: /\bblocked\b/i, label: 'Blocked' },
   149|  { pattern: /\bfailed\b/i, label: 'Failed' },
   150|  { pattern: /\bwaiting\s+for\s+owner\b/i, label: 'Waiting for owner' },
   151|  { pattern: /\bawaiting\s+approval\b/i, label: 'Awaiting approval' },
   152|  { pattern: /\brequires?\s+owner\s+(?:confirmation|approval)\b/i, label: 'Requires owner approval' },
   153|  { pattern: /\bnot\s+verified\b/i, label: 'Not verified' },
   154|  { pattern: /\bunverified\b/i, label: 'Unverified' },
   155|  { pattern: /\bcould\s+not\s+complete\b/i, label: 'Could not complete' },
   156|  { pattern: /\bunable\s+to\b/i, label: 'Unable to' },
   157|];
   158|
   159|function trimmed(value: unknown): string {
   160|  return typeof value === 'string' ? value.trim() : '';
   161|}
   162|
   163|function lower(value: string): string {
   164|  return value.toLowerCase();
   165|}
   166|
   167|/** Detect banned generic promise phrases in an answer. */
   168|export function findBannedGenericPromises(answer: string): string[] {
   169|  const text = lower(answer);
   170|  return BANNED_GENERIC_PROMISES.filter((phrase) => text.includes(phrase));
   171|}
   172|
   173|/** Detect success-state assertions in an answer. */
   174|export function findSuccessStateAssertions(answer: string): string[] {
   175|  return SUCCESS_STATE_PATTERNS.filter(({ pattern }) => pattern.test(answer)).map(
   176|    ({ label }) => label,
   177|  );
   178|}
   179|
   180|/** Detect failure / waiting-state assertions in an answer. */
   181|export function findFailureStateAssertions(answer: string): string[] {
   182|  return FAILURE_STATE_PATTERNS.filter(({ pattern }) => pattern.test(answer)).map(
   183|    ({ label }) => label,
   184|  );
   185|}
   186|
   187|/**
   188| * Evidence required to back a success claim. Returns the list of missing
   189| * evidence fields given the claimed success labels and the attached evidence.
   190| */
   191|export function findMissingEvidence(
   192|  answer: string,
   193|  evidence: IVXIAEvidence | null | undefined,
   194|): string[] {
   195|  const text = answer ?? '';
   196|  const ev = evidence ?? {};
   197|  const missing: string[] = [];
   198|
   199|  const hasTaskId = trimmed(ev.taskId).length > 0 || /\btask\s*id[:\s]+[a-z0-9_-]{4,}/i.test(text);
   200|  const hasFiles = (ev.filesChanged && ev.filesChanged.length > 0)
   201|    || /\bfiles?\s+changed[:\s]+[^\n]+/i.test(text);
   202|  const hasCommit = trimmed(ev.commitSha).length > 0 || /\bcommit(?:_?sha)?[:\s]+[0-9a-f]{6,}/i.test(text);
   203|  const hasDeploy = trimmed(ev.renderDeployId).length > 0
   204|    || /\brender\s+deploy(?:ment)?\s+id[:\s]+[^\s\n]+/i.test(text)
   205|    || /\bdeploy_?id[:\s]+[^\s\n]+/i.test(text);
   206|  const hasLive = trimmed(ev.liveVerification).length > 0
   207|    || /live\s+verification[:\s]+/i.test(text)
   208|    || /production\s+\/health:\s*200/i.test(text)
   209|    || /HTTP\s+200/i.test(text);
   210|
   211|  // A "Verified" / "Deployed" / "Live in production" claim requires the full chain.
   212|  const claimsVerified = /\bverified\b/i.test(text);
   213|  const claimsDeployed = /\bdeployed\b/i.test(text) || /\blive\s+in\s+production\b/i.test(text);
   214|  const claimsDone = /\b(?:done|completed|finished|shipped|fixed)\b/i.test(text);
   215|
   216|  if (claimsDone && !hasFiles) missing.push('Files changed');
   217|  if (claimsDone && !hasTaskId) missing.push('Task ID');
   218|  if ((claimsVerified || claimsDeployed) && !hasCommit) missing.push('Commit SHA');
   219|  if ((claimsVerified || claimsDeployed) && !hasDeploy) missing.push('Render Deploy ID');
   220|  if ((claimsVerified || claimsDeployed) && !hasLive) missing.push('Live verification');
   221|
   222|  return missing;
   223|}
   224|
   225|/**
   226| * Resolve a single decision state from the answer + evidence.
   227| *
   228| * Priority (lowest confidence wins so a contradiction never overclaims):
   229| *  1. If both success and failure assertions are present → contradiction →
   230| *     resolve to the failure side (BLOCKED / FAILED / WAITING_OWNER).
   231| *  2. If a success assertion is present but evidence is missing → UNVERIFIED is
   232| *     NOT a positive state; the gate rewrites the answer, and the state is
   233| *     BLOCKED (the missing evidence is the blocker).
   234| *  3. If only success assertions + full evidence → VERIFIED.
   235| *  4. If only failure assertions → BLOCKED / FAILED / WAITING_OWNER depending on
   236| *     the exact label.
   237| *  5. If only banned promises + no evidence → BLOCKED (generic promise without
   238| *     evidence).
   239| *  6. Otherwise → READY (normal conversational reply, no claim made).
   240| */
   241|export function resolveSingleState(
   242|  answer: string,
   243|  evidence: IVXIAEvidence | null | undefined,
   244|): {
   245|  state: IVXIAState;
   246|  contradictions: string[];
   247|  bannedPromises: string[];
   248|  missingEvidence: string[];
   249|  reason: string | null;
   250|} {
   251|  const successAssertions = findSuccessStateAssertions(answer);
   252|  const failureAssertions = findFailureStateAssertions(answer);
   253|  const bannedPromises = findBannedGenericPromises(answer);
   254|  const missingEvidence = successAssertions.length > 0
   255|    ? findMissingEvidence(answer, evidence)
   256|    : [];
   257|
   258|  // Contradiction: success + failure in the same message.
   259|  const contradictions: string[] = [];
   260|  if (successAssertions.length > 0 && failureAssertions.length > 0) {
   261|    for (const s of successAssertions) {
   262|      for (const f of failureAssertions) {
   263|        contradictions.push(`${s} + ${f}`);
   264|      }
   265|    }
   266|  }
   267|
   268|  if (contradictions.length > 0) {
   269|    // Resolve to the failure side — never overclaim.
   270|    const lowerFailure = failureAssertions.map((f) => lower(f));
   271|    const isWaiting = lowerFailure.some((f) => f.includes('waiting') || f.includes('awaiting') || f.includes('approval'));
   272|    const isFailed = lowerFailure.some((f) => f.includes('failed') || f.includes('could not') || f.includes('unable'));
   273|    const state: IVXIAState = isWaiting ? 'WAITING_OWNER' : isFailed ? 'FAILED' : 'BLOCKED';
   274|    return {
   275|      state,
   276|      contradictions,
   277|      bannedPromises,
   278|      missingEvidence,
   279|      reason: `Contradictory states detected (${contradictions.join('; ')}). Resolved to ${state} — a success claim was retracted because a failure/waiting state appeared in the same reply.`,
   280|    };
   281|  }
   282|
   283|  if (successAssertions.length > 0 && missingEvidence.length > 0) {
   284|    return {
   285|      state: 'BLOCKED',
   286|      contradictions,
   287|      bannedPromises,
   288|      missingEvidence,
   289|      reason: `Success claim (${successAssertions.join(', ')}) without required evidence: ${missingEvidence.join(', ')}.`,
   290|    };
   291|  }
   292|
   293|  if (successAssertions.length > 0 && missingEvidence.length === 0) {
   294|    return { state: 'VERIFIED', contradictions, bannedPromises, missingEvidence, reason: null };
   295|  }
   296|
   297|  if (failureAssertions.length > 0) {
   298|    const lowerFailure = failureAssertions.map((f) => lower(f));
   299|    const isWaiting = lowerFailure.some((f) => f.includes('waiting') || f.includes('awaiting') || f.includes('approval'));
   300|    const isFailed = lowerFailure.some((f) => f.includes('failed') || f.includes('could not') || f.includes('unable'));
   301|    const isNotVerified = lowerFailure.some((f) => f.includes('not verified') || f.includes('unverified'));
   302|    const state: IVXIAState = isWaiting ? 'WAITING_OWNER' : isFailed ? 'FAILED' : isNotVerified ? 'BLOCKED' : 'BLOCKED';
   303|    return { state, contradictions, bannedPromises, missingEvidence, reason: null };
   304|  }
   305|
   306|  if (bannedPromises.length > 0) {
   307|    return {
   308|      state: 'BLOCKED',
   309|      contradictions,
   310|      bannedPromises,
   311|      missingEvidence,
   312|      reason: `Generic promise without evidence: ${bannedPromises.join(', ')}. Inspection has not actually started (no task id or evidence attached).`,
   313|    };
   314|  }
   315|
   316|  return { state: 'READY', contradictions, bannedPromises, missingEvidence, reason: null };
   317|}
   318|
   319|/**
   320| * Build the replacement answer for a gated reply. Always carries exactly one
   321| * state header and the exact blocker / missing evidence / required action.
   322| */
   323|export function buildReliabilityBlockedAnswer(input: {
   324|  state: IVXIAState;
   325|  reason: string;
   326|  missingEvidence: string[];
   327|  contradictions: string[];
   328|  bannedPromises: string[];
   329|}): string {
   330|  const lines: string[] = [];
   331|  lines.push(`STATE: ${input.state}`);
   332|  lines.push('');
   333|
   334|  if (input.contradictions.length > 0) {
   335|    lines.push('CONTRADICTION DETECTED:');
   336|    for (const c of input.contradictions) {
   337|      lines.push(` - ${c}`);
   338|    }
   339|    lines.push('A success claim was retracted because a failure/waiting state appeared in the same reply.');
   340|    lines.push('');
   341|  }
   342|
   343|  if (input.bannedPromises.length > 0) {
   344|    lines.push('GENERIC PROMISE WITHOUT EVIDENCE:');
   345|    for (const p of input.bannedPromises) {
   346|      lines.push(` - "${p}"`);
   347|    }
   348|    lines.push('Inspection / execution has not actually started — no task id or evidence is attached to this turn.');
   349|    lines.push('');
   350|  }
   351|
   352|  if (input.missingEvidence.length > 0) {
   353|    lines.push('MISSING EVIDENCE:');
   354|    for (const m of input.missingEvidence) {
   355|      lines.push(` - ${m}`);
   356|    }
   357|    lines.push('');
   358|  }
   359|
   360|  lines.push(`REASON: ${input.reason}`);
   361|
   362|  if (input.state === 'BLOCKED' || input.state === 'FAILED') {
   363|    lines.push('');
   364|    lines.push('REQUIRED ACTION:');
   365|    if (input.missingEvidence.length > 0) {
   366|      lines.push(` - Provide the missing evidence: ${input.missingEvidence.join(', ')}.`);
   367|    }
   368|    if (input.bannedPromises.length > 0) {
   369|      lines.push(' - Run the real inspection / execution first, then reply with the task id and evidence.');
   370|    }
   371|    if (input.contradictions.length > 0) {
   372|      lines.push(' - Pick exactly one status for this task. Do not assert Done and Blocked in the same reply.');
   373|    }
   374|    if (input.missingEvidence.length === 0 && input.bannedPromises.length === 0 && input.contradictions.length === 0) {
   375|      lines.push(' - See the reason above and resolve the exact blocker.');
   376|    }
   377|  }
   378|
   379|  if (input.state === 'WAITING_OWNER') {
   380|    lines.push('');
   381|    lines.push('REQUIRED ACTION:');
   382|    lines.push(' - Sign in as the owner and explicitly authorize the guarded action to proceed.');
   383|  }
   384|
   385|  lines.push('');
   386|  lines.push('UNVERIFIED — no success claim is valid without the evidence fields above.');
   387|  return lines.join('\n');
   388|}
   389|
   390|/**
   391| * Apply the IVX IA Reliability Gate to a chat answer.
   392| *
   393| * The gate intervenes (rewrites the answer) when:
   394| *  - The answer contradicts itself (success + failure states together).
   395| *  - The answer makes a success claim without the required evidence.
   396| *  - The answer contains a banned generic promise with no evidence.
   397| *
   398| * Otherwise the answer passes through unchanged. The resolved state is always
   399| * returned so the caller can attach it to the response payload.
   400| */
   401|export function applyIVXIAReliabilityGate(
   402|  input: IVXIAReliabilityGateInput,
   403|): IVXIAReliabilityGateResult {
   404|  const answer = trimmed(input.answer);
   405|  const resolution = resolveSingleState(answer, input.evidence);
   406|
   407|  // Pass-through states: READY (no claim), VERIFIED (claim + full evidence),
   408|  // and pure failure/waiting states that have NO contradictions, banned promises,
   409|  // or missing evidence (e.g. an already-BLOCKED senior-developer answer).
   410|  // We only intervene when there is an actual reliability violation to fix.
   411|  const hasViolation =
   412|    resolution.contradictions.length > 0
   413|    || resolution.bannedPromises.length > 0
   414|    || resolution.missingEvidence.length > 0;
   415|
   416|  if (!hasViolation) {
   417|    return {
   418|      answer,
   419|      gated: false,
   420|      state: resolution.state,
   421|      contradictions: resolution.contradictions,
   422|      bannedPromises: resolution.bannedPromises,
   423|      missingEvidence: resolution.missingEvidence,
   424|      reason: resolution.reason,
   425|    };
   426|  }
   427|
   428|  // Intervene: rewrite to a single-state, evidence-first blocked answer.
   429|  const replacement = buildReliabilityBlockedAnswer({
   430|    state: resolution.state,
   431|    reason: resolution.reason ?? 'IVX IA reliability gate intervened.',
   432|    missingEvidence: resolution.missingEvidence,
   433|    contradictions: resolution.contradictions,
   434|    bannedPromises: resolution.bannedPromises,
   435|  });
   436|
   437|  return {
   438|    answer: replacement,
   439|    gated: true,
   440|    state: resolution.state,
   441|    contradictions: resolution.contradictions,
   442|    bannedPromises: resolution.bannedPromises,
   443|    missingEvidence: resolution.missingEvidence,
   444|    reason: resolution.reason,
   445|  };
   446|}

