     1|/**
     2| * IVX Access-Status Narrative Gate.
     3| *
     4| * The IVX Owner AI and public chat are text models. When asked about credentials,
     5| * deployment access, or "end-to-end audit access status", the model has been
     6| * observed claiming it has no direct access to GitHub or Render even when the
     7| * backend is configured with live GITHUB_TOKEN and RENDER_API_KEY. That is a
     8| * false, misleading narrative that undermines owner trust.
     9| *
    10| * This gate:
    11| *  - Detects prompts that ask for an access-status audit.
    12| *  - Detects answers that fabricate a binary "Yes/No" access checklist for
    13| *    Supabase / AWS / GitHub / Render / Vercel.
    14| *  - Replaces the false narrative with a strict, evidence-first answer that
    15| *    instructs the owner to request a live deployment audit (which is the only
    16| *    path that actually exercises the credentials and returns real HTTP proof).
    17| *
    18| * Pure — deterministic, no I/O, no AI, fully unit-testable.
    19| */
    20|
    21|export const IVX_ACCESS_STATUS_NARRATIVE_GATE_MARKER =
    22|  'ivx-access-status-narrative-gate-2026-07-04-v1';
    23|
    24|const ACCESS_STATUS_PROMPT_PATTERNS: RegExp[] = [
    25|  /\bend[-\s]?to[-\s]?end\s+audit\b/i,
    26|  /\bend[-\s]?to[-\s]?end\s+access\b/i,
    27|  /\baccess\s+status\b/i,
    28|  /\baudit\s+access\s+status\b/i,
    29|  /\bdo\s+you\s+have\s+access\b/i,
    30|  /\bwhat\s+access\s+do\s+you\s+have\b/i,
    31|  /\bcredential\s+status\b/i,
    32|  /\bdeployment\s+access\b/i,
    33|  /\bcan\s+you\s+access\s+(github|render|supabase|aws|vercel)\b/i,
    34|];
    35|
    36|const FABRICATED_ACCESS_STATUS_MARKERS: { marker: RegExp; label: string }[] = [
    37|  { marker: /\bend[-\s]?to[-\s]?end\s+audit\s+access\s+status\b/i, label: 'fabricated access-status audit' },
    38|  { marker: /\bSupabase:\s*\*\*Yes\b/i, label: 'fabricated Supabase access badge' },
    39|  { marker: /\bAmazon\s*\(AWS\):\s*\*\*Yes\b/i, label: 'fabricated AWS access badge' },
    40|  { marker: /\bGitHub:\s*\*\*No\b/i, label: 'fabricated GitHub no-access badge' },
    41|  { marker: /\bRender:\s*\*\*No\b/i, label: 'fabricated Render no-access badge' },
    42|  { marker: /\bVercel:\s*\*\*Yes\b/i, label: 'fabricated Vercel access badge' },
    43|  { marker: /No, I (?:currently )?do not have direct access to GitHub repositories/i, label: 'fabricated GitHub no-access claim' },
    44|  { marker: /No, I do not have direct access to Render deployment logs/i, label: 'fabricated Render no-access claim' },
    45|  { marker: /additional credentials would be needed to complete a full audit/i, label: 'fabricated credential-shortfall close' },
    46|];
    47|
    48|export function isAccessStatusPrompt(message: string): boolean {
    49|  const text = typeof message === 'string' ? message : '';
    50|  if (text.trim().length === 0) return false;
    51|  return ACCESS_STATUS_PROMPT_PATTERNS.some((pattern) => pattern.test(text));
    52|}
